64	// Get all running agents from teams config files
65	function getRunningAgents() {
66	  const agents = [];
67	  const descriptions = loadDescriptions();
68	
69	  if (!fs.existsSync(TEAMS_DIR)) return agents;
70	
71	  const teamDirs = fs.readdirSync(TEAMS_DIR);
72	
73	  for (const teamName of teamDirs) {
74	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
75	    try {
76	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
77	
78	      if (config.members && config.members.length > 0) {
79	        for (const member of config.members) {
80	          const agentId = member.agentId;
81	          const descKey = agentId || teamName + '-' + member.name;
82	          const tmuxSession = member.tmuxSession;
83	          const backgroundId = member.backgroundId || teamName;
84	
85	          // Check tmux if available
86	          let sessionAlive = false;
87	          if (tmuxSession) {
88	            sessionAlive = checkTmuxSession(tmuxSession);
89	          } else if (backgroundId) {
90	            const pid = loadPid(`${backgroundId}.pid`);
91	            sessionAlive = checkPidAlive(pid);
92	          }
93	
94	          agents.push({
95	            id: agentId,
96	            name: member.name,
97	            teamName,
98	            type: member.agentType || 'general-purpose',
99	            description: descriptions[descKey] || '',
100	            sessionActive: sessionAlive,
101	            tmuxSession: tmuxSession || null
102	          });
103	        }
104	      }
105	    } catch {
106	      // Skip invalid config files
107	    }
108	  }
109	
110	  return agents;
111	}
