152	// Build environment setup for claude commands
153	function buildEnvScript() {
154	  let settingsEnv = {};
155	  try {
156	    const settingsPath = path.join(process.env.HOME, '.claude', 'settings.json');
157	    const settings = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
158	    settingsEnv = settings.env || {};
159	  } catch (e) {
160	    console.error('Could not read settings.json:', e.message);
161	  }
162	
163	  return {
164	    CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS: settingsEnv.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS || '1',
165	    ANTHROPIC_BASE_URL: settingsEnv.ANTHROPIC_BASE_URL || '',
166	    ANTHROPIC_AUTH_TOKEN: settingsEnv.ANTHROPIC_AUTH_TOKEN || '',
167	    ANTHROPIC_API_KEY: settingsEnv.ANTHROPIC_API_KEY || '',
168	    ANTHROPIC_MODEL: settingsEnv.ANTHROPIC_MODEL || '',
169	    CLAUDE_BIN: settingsEnv.CLAUDE_BIN || path.join(process.env.HOME, '.local', 'bin', 'claude')
170	  };
171	}
