201	// API: Wake up a team by re-spawning the agent in background
202	app.post('/api/wake/:name', (req, res) => {
203	  try {
204	    const teamName = req.params.name;
205	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
206	
207	    if (!fs.existsSync(teamConfigPath)) {
208	      return res.status(404).json({ success: false, error: 'Team not found' });
209	    }
210	
211	    const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
212	    if (!config.members || config.members.length === 0) {
213	      return res.status(400).json({ success: false, error: 'Team has no members' });
214	    }
215	
216	    let results = [];
217	
218	    for (const member of config.members) {
219	      const { name, agentType } = member;
220	      let cmd;
221	      if (name.toLowerCase() === 'trevor' || agentType === 'manager' || agentType === 'trevor') {
222	        cmd = '--agent=trevor -p "Resume your previous work as manager agent."';
223	      } else {
224	        cmd = `-p "Wake up agent ${name}, continue previous work."`;
225	      }
226	
227	      const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
228	      const backgroundId = `${safeName}-${Date.now()}`;
229	      const { bgCmd, logFile } = spawnBackgroundProcess(backgroundId, cmd);
230	
231	      exec(bgCmd, (err, stdout) => {
232	        if (err) {
233	          console.error(`Wake error for ${name}:`, err.message);
234	        } else if (stdout) {
235	          const pid = parseInt(stdout.trim(), 10);
236	          if (pid) savePid(`${teamName}.pid`, pid);
237	          console.log(`Woke up ${name} (PID: ${pid})`);
238	        }
239	      });
240	
241	      member.backgroundId = backgroundId;
242	      results.push({ name: member.name, logFile, status: 'waking_up' });
243	    }
244	
245	    // Save updated config with new background IDs
246	    fs.writeFileSync(teamConfigPath, JSON.stringify(config, null, 2));
247	
248	    res.json({ success: true, message: `Woke up team "${teamName}"`, agents: results });
249	  } catch (err) {
250	    res.status(500).json({ success: false, error: err.message });
251	  }
252	});
