349	// API: Shutdown and clean up a team
350	app.delete('/api/teams/:name', (req, res) => {
351	  try {
352	    const teamName = req.params.name;
353	    const teamPath = path.join(TEAMS_DIR, teamName);
354	    const taskPath = path.join(CLAUDE_DIR, 'tasks', teamName);
355	    const pidFile = path.join(PID_DIR, `${teamName}.pid`);
356	
357	    // Kill background process if running
358	    if (fs.existsSync(pidFile)) {
359	      const pid = loadPid(`${teamName}.pid`);
360	      if (pid && checkPidAlive(pid)) {
361	        process.kill(pid, 'SIGTERM');
362	        console.log(`Killed PID ${pid}`);
363	      }
364	      fs.unlinkSync(pidFile);
365	    }
366	
367	    if (fs.existsSync(teamPath)) {
368	      try {
369	        fs.rmSync(teamPath, { recursive: true, force: true });
370	      } catch (e) {
371	        const configFile = path.join(teamPath, 'config.json');
372	        if (fs.existsSync(configFile)) fs.unlinkSync(configFile);
373	      }
374	    }
375	    if (fs.existsSync(taskPath)) {
376	      fs.rmSync(taskPath, { recursive: true, force: true });
377	    }
378	
379	    res.json({ success: true, message: `Team "${teamName}" removed` });
380	  } catch (err) {
381	    res.status(500).json({ success: false, error: err.message });
382	  }
383	});
